+  const ampm = hours >= 12 ? 'PM' : 'AM';
+  hours = hours % 12 || 12; 
+  const formattedHours = String(hours).padStart(2, '0');
+  
+  return `${month}/${day}/${year} ${formattedHours}:${minutes}:${seconds} ${ampm}`;
+
